import React from "react";
import { Plus } from "lucide-react";

export default function GoalsScreen({ goals = [] }) {
  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      {/* Header */}
      <div className="flex items-center justify-between pt-6 mb-6">
        <h1 className="text-2xl font-bold">Savings Goals</h1>

        {/* Add goal (logic later) */}
        <button className="p-2 rounded-full bg-emerald-600 text-white hover:bg-emerald-700">
          <Plus size={20} />
        </button>
      </div>

      {/* Empty state */}
      {goals.length === 0 ? (
        <div className="bg-white p-6 rounded-2xl border border-gray-100 text-center">
          <p className="text-gray-500 mb-4">
            You don’t have any savings goals yet.
          </p>
          <button className="px-4 py-2 bg-emerald-600 text-white rounded-xl">
            Create your first goal
          </button>
        </div>
      ) : (
        <div className="space-y-4">
          {goals.map((g) => {
            const progress = Math.min(
              Math.round((g.amountSaved / g.targetAmount) * 100),
              100
            );

            return (
              <div
                key={g.id}
                className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm"
              >
                <div className="flex justify-between items-center mb-2">
                  <h2 className="font-semibold text-gray-800">{g.title}</h2>
                  <span className="text-sm text-gray-400">{progress}%</span>
                </div>

                <p className="text-sm text-gray-500 mb-4">
                  {g.description}
                </p>

                {/* Progress bar */}
                <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden mb-3">
                  <div
                    className="h-full bg-emerald-600"
                    style={{ width: `${progress}%` }}
                  />
                </div>

                <div className="flex justify-between items-center text-sm">
                  <span className="text-gray-500">
                    Saved: <strong>${g.amountSaved}</strong>
                  </span>
                  <span className="text-gray-500">
                    Target: <strong>${g.targetAmount}</strong>
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
